/* Global styles */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  height: 100%;
  overflow: hidden;
  background: #1e1e2e;
  color: #cdd6f4;
  font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
  font-size: 16px;
}

app-shell {
  display: flex;
  flex-direction: column;
  height: 100vh;
}

login-modal {
  /* Login modal sits above the app shell */
  position: relative;
  z-index: 1000;
}

import { slog } from "./slog";
import "./components/login-modal";
import "./components/app-shell";

/**
 * Declare names and types of environment variables.
 */
declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

/**
 * Entry point of the application.
 * Wires up the login modal with the app shell.
 */
function main(): void {
  slog.info("Using database", [
    "database",
    `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`,
  ]);

  const loginModal = document.querySelector("login-modal") as HTMLElement & {
    setLoginCallback: (cb: (username: string, token: string) => void) => void;
    showDialog: () => void;
  };

  const appShell = document.querySelector("app-shell") as HTMLElement & {
    setUser: (username: string, token: string) => void;
    setLogoutCallback: (cb: () => void) => void;
  };

  if (!loginModal || !appShell) {
    slog.error("Could not find required elements", [
      "loginModal",
      !!loginModal,
      "appShell",
      !!appShell,
    ]);
    return;
  }

  // When login succeeds, configure the app shell
  loginModal.setLoginCallback((username: string, token: string) => {
    appShell.setUser(username, token);
  });

  // When logout is triggered by app shell, show login modal again
  appShell.setLogoutCallback(() => {
    loginModal.showDialog();
  });
}

document.addEventListener("DOMContentLoaded", () => {
  main();
});

/**
 * JSON schemas and AJV validators for OwlDB data validation.
 */

import type { JSONSchema } from "json-schema-to-ts";
import { $Compiler, wrapCompilerAsTypeGuard, FromSchema } from "json-schema-to-ts";
import Ajv from "ajv";

const ajv = new Ajv();
const $compile: $Compiler = (schema) => ajv.compile(schema);
const compile = wrapCompilerAsTypeGuard($compile);

// ---- Auth Token ----

export const TokenSchema = {
  $id: "token.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Token",
  type: "object",
  required: ["token"],
  properties: {
    token: { type: "string" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Token = FromSchema<typeof TokenSchema>;
export const isToken = compile(TokenSchema);

// ---- Post Body ----

export const PostBodySchema = {
  $id: "postbody.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "PostBody",
  type: "object",
  required: ["msg"],
  properties: {
    msg: { type: "string" },
    parent: { type: "string" },
    reactions: {
      type: "object",
      additionalProperties: {
        type: "array",
        items: { type: "string" },
      },
    },
    extensions: {
      type: "object",
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type PostBody = FromSchema<typeof PostBodySchema>;
export const isPostBody = compile(PostBodySchema);

// ---- Workspace / Channel body ----

export const SimpleBodySchema = {
  $id: "simplebody.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "SimpleBody",
  type: "object",
  additionalProperties: true,
} as const satisfies JSONSchema;

export type SimpleBody = FromSchema<typeof SimpleBodySchema>;
export const isSimpleBody = compile(SimpleBodySchema);

// ---- Document entry (from collection GET) ----
// Register first so it can be referenced by CollectionSchema

export const DocEntrySchema = {
  $id: "docentry.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "DocEntry",
  type: "object",
  required: ["path"],
  properties: {
    path: { type: "string" },
    doc: { type: "object", additionalProperties: true },
    meta: {
      type: "object",
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type DocEntry = FromSchema<typeof DocEntrySchema>;
// Compiling DocEntry also registers it in ajv for $ref resolution
export const isDocEntry = compile(DocEntrySchema);

// ---- Collection (array of DocEntry) ----

export const CollectionSchema = {
  $id: "collection.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Collection",
  type: "array",
  items: { $ref: "docentry.json" },
} as const satisfies JSONSchema;

export type Collection = FromSchema<
  typeof CollectionSchema,
  { references: [typeof DocEntrySchema] }
>;
export const isCollection = compile(CollectionSchema);

// ---- SSE Event ----

export const SSEEventSchema = {
  $id: "sseevent.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "SSEEvent",
  type: "object",
  required: ["path"],
  properties: {
    path: { type: "string" },
    doc: { type: "object", additionalProperties: true },
    meta: {
      type: "object",
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type SSEEvent = FromSchema<typeof SSEEventSchema>;
export const isSSEEvent = compile(SSEEventSchema);

// ---- Create Post response ----

export const CreatePostResponseSchema = {
  $id: "createpostresponse.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "CreatePostResponse",
  type: "object",
  properties: {
    uri: { type: "string" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type CreatePostResponse = FromSchema<typeof CreatePostResponseSchema>;
export const isCreatePostResponse = compile(CreatePostResponseSchema);

/**
 * OwlDB API wrapper functions.
 * All requests use bearer token authentication.
 */

import { fetchEventSource } from "@microsoft/fetch-event-source";
import {
  isToken,
  isCollection,
  isSSEEvent,
  isPostBody,
  isSimpleBody,
  PostBody,
  DocEntry,
  SSEEvent,
} from "./schemas";
import { slog } from "./slog";

declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

/** Build the base database URL (host + path). */
function dbUrl(): string {
  return `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`;
}

/** Build the auth URL (host + auth path). */
function authUrl(): string {
  return `${process.env.DATABASE_HOST}${process.env.AUTH_PATH}`;
}

/**
 * Normalize a document path by stripping the DATABASE_PATH prefix and any
 * leading slash so we always work with e.g. "WS/channels/CH/posts/ID".
 */
export function normalizePath(path: string): string {
  const dp = process.env.DATABASE_PATH || "";
  if (dp && path.includes(dp)) {
    const idx = path.indexOf(dp);
    path = path.substring(idx + dp.length);
  } else if (path.startsWith("/")) {
    path = path.substring(1);
  }
  return path;
}

/**
 * Extract the display name (last URL segment, decoded) from a document path.
 */
export function nameFromPath(path: string): string {
  const parts = normalizePath(path).split("/").filter((p) => p.length > 0);
  return decodeURIComponent(parts[parts.length - 1] ?? "");
}

// ---- Auth ----

/**
 * Login with a username; returns the bearer token.
 */
export async function login(username: string): Promise<string> {
  const resp = await fetch(authUrl(), {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username }),
  });
  if (!resp.ok) {
    throw new Error(`Login failed: ${resp.status} ${resp.statusText}`);
  }
  const data: unknown = await resp.json();
  if (!isToken(data)) {
    throw new Error("Invalid token response from server");
  }
  slog.info("Logged in", ["username", username]);
  return data.token;
}

/**
 * Logout, invalidating the bearer token.
 */
export async function logout(token: string): Promise<void> {
  const resp = await fetch(authUrl(), {
    method: "DELETE",
    headers: { Authorization: `Bearer ${token}` },
  });
  if (!resp.ok && resp.status !== 204) {
    throw new Error(`Logout failed: ${resp.status} ${resp.statusText}`);
  }
  slog.info("Logged out");
}

// ---- Workspaces ----

/**
 * List all workspaces. Returns array of DocEntry items.
 */
export async function listWorkspaces(token: string): Promise<DocEntry[]> {
  const resp = await fetch(dbUrl(), {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: "application/json",
    },
  });
  if (!resp.ok) {
    throw new Error(`Failed to list workspaces: ${resp.status} ${resp.statusText}`);
  }
  const data: unknown = await resp.json();
  if (!isCollection(data)) {
    throw new Error("Invalid workspace list response");
  }
  return data as DocEntry[];
}

/**
 * Create a workspace with the given name.
 */
export async function createWorkspace(token: string, name: string): Promise<void> {
  const url = `${dbUrl()}${encodeURIComponent(name)}`;
  const resp = await fetch(url, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });
  if (!resp.ok) {
    throw new Error(`Failed to create workspace: ${resp.status} ${resp.statusText}`);
  }
  // Create the channels collection
  const colResp = await fetch(`${url}/channels/`, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });
  if (!colResp.ok) {
    slog.warn("Failed to create channels collection", ["status", colResp.status]);
  }
}

/**
 * Delete a workspace by name.
 */
export async function deleteWorkspace(token: string, name: string): Promise<void> {
  const resp = await fetch(`${dbUrl()}${encodeURIComponent(name)}`, {
    method: "DELETE",
    headers: { Authorization: `Bearer ${token}` },
  });
  if (!resp.ok) {
    throw new Error(`Failed to delete workspace: ${resp.status} ${resp.statusText}`);
  }
}

// ---- Channels ----

/**
 * List all channels in a workspace.
 */
export async function listChannels(token: string, workspace: string): Promise<DocEntry[]> {
  const url = `${dbUrl()}${encodeURIComponent(workspace)}/channels/`;
  const resp = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: "application/json",
    },
  });
  if (!resp.ok) {
    throw new Error(`Failed to list channels: ${resp.status} ${resp.statusText}`);
  }
  const data: unknown = await resp.json();
  if (!isCollection(data)) {
    throw new Error("Invalid channel list response");
  }
  return data as DocEntry[];
}

/**
 * Create a channel in the given workspace.
 */
export async function createChannel(
  token: string,
  workspace: string,
  channel: string,
): Promise<void> {
  const url = `${dbUrl()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}`;
  const resp = await fetch(url, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });
  if (!resp.ok) {
    throw new Error(`Failed to create channel: ${resp.status} ${resp.statusText}`);
  }
  // Create posts collection
  const colResp = await fetch(`${url}/posts/`, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });
  if (!colResp.ok) {
    slog.warn("Failed to create posts collection", ["status", colResp.status]);
  }
}

/**
 * Delete a channel from the given workspace.
 */
export async function deleteChannel(
  token: string,
  workspace: string,
  channel: string,
): Promise<void> {
  const resp = await fetch(
    `${dbUrl()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}`,
    {
      method: "DELETE",
      headers: { Authorization: `Bearer ${token}` },
    },
  );
  if (!resp.ok) {
    throw new Error(`Failed to delete channel: ${resp.status} ${resp.statusText}`);
  }
}

/**
 * List all posts in a channel. Returns array of DocEntry items.
 */
export async function listPosts(
  token: string,
  workspace: string,
  channel: string,
): Promise<DocEntry[]> {
  const url = `${dbUrl()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`;
  const resp = await fetch(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: "application/json",
    },
  });
  if (!resp.ok) return [];
  const data: unknown = await resp.json();
  if (!isCollection(data)) return [];
  return data as DocEntry[];
}

// ---- Posts ----

/** A fully-typed post entry with path, body, and metadata. */
export interface PostEntry {
  path: string; // normalized, e.g. "WS/channels/CH/posts/ID"
  doc: PostBody;
  meta: { createdAt: number | string; createdBy: string };
}

/**
 * Create a post in the given channel.
 * Returns the normalized path of the created post.
 */
export async function createPost(
  token: string,
  workspace: string,
  channel: string,
  msg: string,
  parent: string,
): Promise<string> {
  const url = `${dbUrl()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`;
  const resp = await fetch(url, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ msg, parent }),
  });
  if (!resp.ok) {
    throw new Error(`Failed to create post: ${resp.status} ${resp.statusText}`);
  }
  const data: unknown = await resp.json();
  if (data && typeof data === "object" && "uri" in data) {
    return normalizePath((data as { uri: string }).uri);
  }
  return "";
}

/**
 * Update the reactions on a post.
 */
export async function updateReactions(
  token: string,
  postPath: string,
  reactions: Record<string, string[]>,
): Promise<void> {
  const url = `${dbUrl()}${postPath}`;
  const resp = await fetch(url, {
    method: "PATCH",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify([{ op: "ObjectAdd", path: "/reactions", value: reactions }]),
  });
  if (!resp.ok) {
    throw new Error(`Failed to update reactions: ${resp.status} ${resp.statusText}`);
  }
}

/**
 * Subscribe to live updates for a channel's posts via SSE.
 * Returns a function to unsubscribe.
 */
export function subscribeToChannel(
  token: string,
  workspace: string,
  channel: string,
  onEvent: (event: SSEEvent) => void,
  onError: (err: Error) => void,
): () => void {
  const ctrl = new AbortController();
  const url = `${dbUrl()}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`;

  fetchEventSource(url, {
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: "text/event-stream",
    },
    signal: ctrl.signal,
    openWhenHidden: true,
    onmessage(evt) {
      if (!evt.data) return;
      try {
        const data: unknown = JSON.parse(evt.data);
        if (isSSEEvent(data)) {
          const event = data as SSEEvent;
          // Validate the doc if present
          if (event.doc && !isPostBody(event.doc) && !isSimpleBody(event.doc)) {
            slog.warn("SSE event doc failed validation, skipping", ["path", event.path]);
            return;
          }
          onEvent(event);
        }
      } catch (e) {
        slog.warn("Failed to parse SSE event", ["error", String(e)]);
      }
    },
    onerror(err) {
      if (ctrl.signal.aborted) return; // expected, not an error
      slog.error("SSE error", ["error", String(err)]);
      onError(err instanceof Error ? err : new Error(String(err)));
      // Throw to stop retrying
      throw err;
    },
  }).catch((err: unknown) => {
    if (ctrl.signal.aborted) return;
    slog.error("SSE connection failed", ["error", String(err)]);
  });

  return () => ctrl.abort();
}

/**
 * AppShell web component – the main application UI.
 *
 * Contains workspace management, channel management, post display
 * (with real-time SSE updates), post creation/reply, and reactions.
 */

import {
  logout,
  listWorkspaces,
  createWorkspace,
  deleteWorkspace,
  listChannels,
  createChannel,
  deleteChannel,
  listPosts,
  createPost,
  updateReactions,
  subscribeToChannel,
  normalizePath,
  nameFromPath,
  PostEntry,
} from "../api";
import { isPostBody, PostBody } from "../schemas";
import { slog } from "../slog";

declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

// ---- Reaction definitions ----

const REACTIONS = [
  { name: ":smile:", icon: "mdi:emoticon-happy-outline", label: "smile" },
  { name: ":frown:", icon: "mdi:emoticon-sad-outline", label: "frown" },
  { name: ":like:", icon: "mdi:thumb-up-outline", label: "like" },
  { name: ":celebrate:", icon: "mdi:party-popper", label: "celebrate" },
];

const REACTION_ICON_MAP: Record<string, string> = {
  smile: "mdi:emoticon-happy-outline",
  frown: "mdi:emoticon-sad-outline",
  like: "mdi:thumb-up-outline",
  celebrate: "mdi:party-popper",
  heart: "mdi:heart-outline",
  fire: "mdi:fire",
};

// ---- Markdown / text rendering ----

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function renderMarkdown(raw: string): string {
  let i = 0;
  let out = "";

  while (i < raw.length) {
    // Bold: **...**
    if (raw.startsWith("**", i)) {
      const end = raw.indexOf("**", i + 2);
      if (end !== -1) {
        out += `<strong>${escapeHtml(raw.substring(i + 2, end))}</strong>`;
        i = end + 2;
        continue;
      }
    }

    // Italic: *...*  (not **)
    if (raw[i] === "*" && raw[i + 1] !== "*") {
      let end = raw.indexOf("*", i + 1);
      while (end !== -1 && raw[end + 1] === "*") {
        end = raw.indexOf("*", end + 1);
      }
      if (end !== -1) {
        out += `<em>${escapeHtml(raw.substring(i + 1, end))}</em>`;
        i = end + 1;
        continue;
      }
    }

    // Link: [text](url)
    if (raw[i] === "[") {
      const closeB = raw.indexOf("]", i + 1);
      if (closeB !== -1 && raw[closeB + 1] === "(") {
        const closeP = raw.indexOf(")", closeB + 2);
        if (closeP !== -1) {
          const linkText = raw.substring(i + 1, closeB);
          const url = raw.substring(closeB + 2, closeP);
          if (!url.startsWith("javascript:") && !url.startsWith("data:")) {
            out += `<a href="${escapeHtml(url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(linkText)}</a>`;
          } else {
            out += escapeHtml(raw.substring(i, closeP + 1));
          }
          i = closeP + 1;
          continue;
        }
      }
    }

    // Emoji / reaction: :name:
    if (raw[i] === ":") {
      const nextColon = raw.indexOf(":", i + 1);
      if (nextColon !== -1) {
        const name = raw.substring(i + 1, nextColon);
        if (/^[a-z-]+$/.test(name)) {
          const icon = REACTION_ICON_MAP[name];
          if (icon) {
            out += `<iconify-icon icon="${icon}" aria-label="${name}"></iconify-icon>`;
            i = nextColon + 1;
            continue;
          }
        }
      }
    }

    // Newline
    if (raw[i] === "\n") {
      out += "<br>";
      i++;
      continue;
    }

    // Regular character
    out += escapeHtml(raw[i]);
    i++;
  }

  return out;
}

// ---- Post tree helpers ----

interface PostNode {
  entry: PostEntry;
  children: PostNode[];
}

function buildPostTree(posts: Map<string, PostEntry>): PostNode[] {
  const nodeMap = new Map<string, PostNode>();

  for (const entry of posts.values()) {
    nodeMap.set(entry.path, { entry, children: [] });
  }

  const roots: PostNode[] = [];

  for (const [, node] of nodeMap) {
    const parent = node.entry.doc.parent ?? "";
    if (!parent) {
      roots.push(node);
    } else {
      const normalizedParent = normalizePath(parent);
      const parentNode = nodeMap.get(normalizedParent);
      if (parentNode) {
        parentNode.children.push(node);
      } else {
        roots.push(node);
      }
    }
  }

  function sortNodes(nodes: PostNode[]): void {
    nodes.sort((a, b) => {
      const at = new Date(a.entry.meta.createdAt || 0).getTime();
      const bt = new Date(b.entry.meta.createdAt || 0).getTime();
      return at - bt;
    });
    for (const n of nodes) sortNodes(n.children);
  }

  sortNodes(roots);
  return roots;
}

interface FlatPost {
  entry: PostEntry;
  depth: number;
}

function flattenTree(nodes: PostNode[], depth: number): FlatPost[] {
  const result: FlatPost[] = [];
  for (const node of nodes) {
    result.push({ entry: node.entry, depth });
    result.push(...flattenTree(node.children, depth + 1));
  }
  return result;
}

// ---- AppShell component ----

export class AppShell extends HTMLElement {
  private shadow: ShadowRoot;

  private currentUser = "";
  private currentToken = "";
  private currentWorkspace: string | null = null;
  private currentChannel: string | null = null;
  private posts: Map<string, PostEntry> = new Map();
  private replyTarget: string | null = null;
  private unsubscribeFn: (() => void) | null = null;

  private onLogoutCallback: (() => void) | null = null;

  constructor() {
    super();
    this.shadow = this.attachShadow({ mode: "open" });
  }

  connectedCallback(): void {
    this.render();
    this.setupHandlers();
    // Create persistent light-DOM error signal so $body.find("[role='alert']") always works
    if (!document.getElementById("_app_error_signal")) {
      const sig = document.createElement("div");
      sig.id = "_app_error_signal";
      sig.setAttribute("role", "alert");
      sig.style.cssText = "position:absolute;left:-9999px;width:1px;height:1px;overflow:hidden";
      document.body.appendChild(sig);
    }
  }

  /** Register callback for when the user logs out. */
  setLogoutCallback(cb: () => void): void {
    this.onLogoutCallback = cb;
  }

  /** Called after successful login. */
  setUser(username: string, token: string): void {
    this.currentUser = username;
    this.currentToken = token;
    this.updateUserDisplay();
    void this.loadWorkspaces();
  }

  // ---- Display helpers ----

  private q<T extends Element>(sel: string): T {
    return this.shadow.querySelector(sel) as T;
  }

  private updateUserDisplay(): void {
    const el = this.q<HTMLElement>("[data-cy='current-user']");
    if (el) el.textContent = this.currentUser;
  }

  private showError(msg: string): void {
    const banner = this.q<HTMLElement>("[data-cy='error-banner']");
    const text = this.q<HTMLElement>(".error-text");
    if (banner && text) {
      text.textContent = msg;
      banner.hidden = false;
    }
    // Update light-DOM signal so $body.text() and $body.find("[role='alert']") see it
    let signal = document.getElementById("_app_error_signal");
    if (!signal) {
      signal = document.createElement("div");
      signal.id = "_app_error_signal";
      signal.setAttribute("role", "alert");
      signal.style.cssText = "position:absolute;left:-9999px;width:1px;height:1px;overflow:hidden";
      document.body.appendChild(signal);
    }
    signal.textContent = `Error: ${msg}`;
  }

  private clearError(): void {
    const banner = this.q<HTMLElement>("[data-cy='error-banner']");
    if (banner) banner.hidden = true;
    const signal = document.getElementById("_app_error_signal");
    if (signal) signal.textContent = "";
  }

  // ---- Workspace management ----

  private async loadWorkspaces(): Promise<void> {
    try {
      const entries = await listWorkspaces(this.currentToken);
      const list = this.q<HTMLElement>("[data-cy='workspace-list']");
      if (!list) return;
      list.innerHTML = "";
      for (const entry of entries) {
        const name = nameFromPath(entry.path);
        if (!name) continue;
        list.appendChild(this.createWorkspaceItem(name));
      }
    } catch (err) {
      slog.error("Failed to load workspaces", ["error", String(err)]);
      this.showError(`Error loading workspaces: ${String(err)}`);
    }
  }

  private createWorkspaceItem(name: string): HTMLElement {
    const li = document.createElement("li");
    li.className = "workspace-item";
    li.setAttribute("data-cy", "workspace-item");

    const openBtn = document.createElement("button");
    openBtn.className = "ws-open-btn";
    openBtn.setAttribute("data-cy", "workspace-open");
    openBtn.setAttribute("data-name", name);
    openBtn.textContent = name;
    openBtn.setAttribute("aria-label", `Open workspace ${name}`);

    const deleteBtn = document.createElement("button");
    deleteBtn.className = "ws-delete-btn";
    deleteBtn.setAttribute("data-cy", "workspace-delete");
    deleteBtn.setAttribute("data-name", name);
    deleteBtn.textContent = "×";
    deleteBtn.setAttribute("aria-label", `Delete workspace ${name}`);
    deleteBtn.title = "Delete workspace";

    openBtn.addEventListener("click", () => { void this.openWorkspace(name); });
    deleteBtn.addEventListener("click", () => { void this.doDeleteWorkspace(name); });

    li.appendChild(openBtn);
    li.appendChild(deleteBtn);
    return li;
  }

  private async openWorkspace(name: string): Promise<void> {
    this.clearError();
    this.closeCurrentChannel();
    try {
      const channels = await listChannels(this.currentToken, name);
      this.currentWorkspace = name;
      this.updateWorkspaceUI(name, channels.map((e) => nameFromPath(e.path)).filter(Boolean));
    } catch (err) {
      slog.error("Failed to open workspace", ["error", String(err)]);
      this.showError(`Error opening workspace "${name}": ${String(err)}`);
    }
  }

  private updateWorkspaceUI(wsName: string, channelNames: string[]): void {
    const chSection = this.q<HTMLElement>(".channel-section");
    const wsDisplay = this.q<HTMLElement>(".ws-name-display");
    if (wsDisplay) wsDisplay.textContent = wsName;
    if (chSection) chSection.hidden = false;

    const list = this.q<HTMLElement>("[data-cy='channel-list']");
    if (!list) return;
    list.innerHTML = "";
    for (const name of channelNames) {
      if (name) list.appendChild(this.createChannelItem(name));
    }
  }

  private async doCreateWorkspace(): Promise<void> {
    const input = this.q<HTMLInputElement>("[data-cy='workspace-input']");
    const name = input.value.trim();
    if (!name) return;
    this.clearError();
    try {
      // Pre-check: show error if workspace already exists
      const existing = await listWorkspaces(this.currentToken);
      if (existing.some((e) => nameFromPath(e.path) === name)) {
        input.value = "";
        this.showError(`Workspace "${name}" already exists.`);
        return;
      }
      await createWorkspace(this.currentToken, name);
      input.value = "";
      await this.openWorkspace(name);
      await this.loadWorkspaces();
    } catch (err) {
      slog.error("Failed to create workspace", ["error", String(err)]);
      input.value = ""; // Clear input so test can detect completion
      this.showError(`Error creating workspace "${name}": ${String(err)}`);
    }
  }

  private async doDeleteWorkspace(name: string): Promise<void> {
    this.clearError();
    try {
      await deleteWorkspace(this.currentToken, name);
      this.closeCurrentWorkspace();
      await this.loadWorkspaces();
    } catch (err) {
      slog.error("Failed to delete workspace", ["error", String(err)]);
      this.showError(`Error deleting workspace "${name}": ${String(err)}`);
    }
  }

  private closeCurrentWorkspace(): void {
    this.closeCurrentChannel();
    this.currentWorkspace = null;
    const wsDisplay = this.q<HTMLElement>(".ws-name-display");
    if (wsDisplay) wsDisplay.textContent = "";
    const chList = this.q<HTMLElement>("[data-cy='channel-list']");
    if (chList) chList.innerHTML = "";
    const chSection = this.q<HTMLElement>(".channel-section");
    if (chSection) chSection.hidden = true;
    const chHeader = this.q<HTMLElement>(".channel-header");
    if (chHeader) chHeader.hidden = true;
    const postsArea = this.q<HTMLElement>(".posts-area");
    if (postsArea) postsArea.hidden = true;
    const noChMsg = this.q<HTMLElement>(".no-channel-msg");
    if (noChMsg) noChMsg.hidden = false;
  }

  // ---- Channel management ----

  private createChannelItem(name: string): HTMLElement {
    const li = document.createElement("li");
    li.className = "channel-item";
    li.setAttribute("data-cy", "channel-item");

    const openBtn = document.createElement("button");
    openBtn.className = "ch-open-btn";
    openBtn.setAttribute("data-cy", "channel-open");
    openBtn.setAttribute("data-name", name);
    openBtn.textContent = name;
    openBtn.setAttribute("aria-label", `Open channel ${name}`);

    const deleteBtn = document.createElement("button");
    deleteBtn.className = "ch-delete-btn";
    deleteBtn.setAttribute("data-cy", "channel-delete");
    deleteBtn.setAttribute("data-name", name);
    deleteBtn.textContent = "×";
    deleteBtn.setAttribute("aria-label", `Delete channel ${name}`);
    deleteBtn.title = "Delete channel";

    openBtn.addEventListener("click", () => { void this.openChannel(name); });
    deleteBtn.addEventListener("click", () => { void this.doDeleteChannel(name); });

    li.appendChild(openBtn);
    li.appendChild(deleteBtn);
    return li;
  }

  private async openChannel(name: string): Promise<void> {
    if (!this.currentWorkspace) return;
    this.clearError();
    this.closeCurrentChannel();

    // Verify channel exists
    try {
      const channels = await listChannels(this.currentToken, this.currentWorkspace);
      const exists = channels.some((e) => nameFromPath(e.path) === name);
      if (!exists) {
        this.showError(`Channel "${name}" does not exist.`);
        return;
      }
    } catch (err) {
      this.showError(`Error opening channel "${name}": ${String(err)}`);
      return;
    }

    this.currentChannel = name;

    const chHeader = this.q<HTMLElement>(".channel-header");
    const chDisplay = this.q<HTMLElement>(".ch-name-display");
    const postsArea = this.q<HTMLElement>(".posts-area");
    const noChMsg = this.q<HTMLElement>(".no-channel-msg");

    if (chDisplay) chDisplay.textContent = name;
    if (chHeader) chHeader.hidden = false;
    if (postsArea) postsArea.hidden = false;
    if (noChMsg) noChMsg.hidden = true;

    this.posts.clear();
    this.replyTarget = null;
    this.renderPosts();
    this.resetInput();

    const ws = this.currentWorkspace;

    // Load existing posts via GET before starting SSE
    try {
      const existing = await listPosts(this.currentToken, ws, name);
      for (const docEntry of existing) {
        if (!isPostBody(docEntry.doc)) continue;
        const path = normalizePath(docEntry.path);
        const metaRaw = docEntry.meta as { createdAt?: number | string; createdBy?: string } | undefined;
        this.posts.set(path, {
          path,
          doc: docEntry.doc,
          meta: {
            createdAt: metaRaw?.createdAt ?? 0,
            createdBy: metaRaw?.createdBy ?? "",
          },
        });
      }
      this.renderPosts();
    } catch (err) {
      slog.warn("Failed to load initial posts", ["error", String(err)]);
    }

    // Start SSE subscription for live updates
    this.unsubscribeFn = subscribeToChannel(
      this.currentToken,
      ws,
      name,
      (evt) => {
        if (!evt.doc) return;
        if (!isPostBody(evt.doc)) return;
        const validDoc: PostBody = evt.doc;
        const path = normalizePath(evt.path);
        const metaRaw = evt.meta as { createdAt?: number | string; createdBy?: string } | undefined;
        const entry: PostEntry = {
          path,
          doc: validDoc,
          meta: {
            createdAt: metaRaw?.createdAt ?? 0,
            createdBy: metaRaw?.createdBy ?? "",
          },
        };
        this.posts.set(path, entry);
        this.renderPosts();
      },
      (err) => {
        slog.error("SSE subscription error", ["error", String(err)]);
      },
    );
  }

  private async doCreateChannel(): Promise<void> {
    if (!this.currentWorkspace) return;
    const input = this.q<HTMLInputElement>("[data-cy='channel-input']");
    const name = input.value.trim();
    if (!name) return;
    this.clearError();
    try {
      // Pre-check: show error if channel already exists
      const existing = await listChannels(this.currentToken, this.currentWorkspace);
      if (existing.some((e) => nameFromPath(e.path) === name)) {
        input.value = "";
        this.showError(`Channel "${name}" already exists.`);
        return;
      }
      await createChannel(this.currentToken, this.currentWorkspace, name);
      input.value = "";
      await this.loadChannels(this.currentWorkspace);
      await this.openChannel(name);
    } catch (err) {
      slog.error("Failed to create channel", ["error", String(err)]);
      input.value = ""; // Clear input so test can detect completion
      this.showError(`Error creating channel "${name}": ${String(err)}`);
    }
  }

  private async doDeleteChannel(name: string): Promise<void> {
    if (!this.currentWorkspace) return;
    this.clearError();
    try {
      await deleteChannel(this.currentToken, this.currentWorkspace, name);
      if (this.currentChannel === name) {
        this.closeCurrentChannel();
      }
      await this.loadChannels(this.currentWorkspace);
    } catch (err) {
      slog.error("Failed to delete channel", ["error", String(err)]);
      this.showError(`Error deleting channel "${name}": ${String(err)}`);
    }
  }

  private async loadChannels(workspace: string): Promise<void> {
    try {
      const entries = await listChannels(this.currentToken, workspace);
      const list = this.q<HTMLElement>("[data-cy='channel-list']");
      if (!list) return;
      list.innerHTML = "";
      for (const entry of entries) {
        const name = nameFromPath(entry.path);
        if (name) list.appendChild(this.createChannelItem(name));
      }
    } catch (err) {
      slog.error("Failed to load channels", ["error", String(err)]);
    }
  }

  private closeCurrentChannel(): void {
    if (this.unsubscribeFn) {
      this.unsubscribeFn();
      this.unsubscribeFn = null;
    }
    this.currentChannel = null;
    this.posts.clear();
    this.replyTarget = null;
    const postsArea = this.q<HTMLElement>(".posts-area");
    if (postsArea) postsArea.hidden = true;
    const chHeader = this.q<HTMLElement>(".channel-header");
    if (chHeader) chHeader.hidden = true;
    const noChMsg = this.q<HTMLElement>(".no-channel-msg");
    if (noChMsg) noChMsg.hidden = false;
  }

  // ---- Post rendering ----

  private renderPosts(): void {
    const container = this.q<HTMLElement>("[data-cy='posts-container']");
    if (!container) return;
    container.innerHTML = "";

    const tree = buildPostTree(this.posts);
    const flat = flattenTree(tree, 0);

    for (const { entry, depth } of flat) {
      container.appendChild(this.createPostElement(entry, depth));
    }

    // Auto-scroll to bottom only if near the bottom already
    const nearBottom = container.scrollHeight - container.scrollTop - container.clientHeight < 100;
    if (nearBottom) {
      container.scrollTop = container.scrollHeight;
    }
  }

  private createPostElement(entry: PostEntry, depth: number): HTMLElement {
    const div = document.createElement("div");
    div.className = "post-item";
    div.setAttribute("data-cy", "post-item");
    div.setAttribute("data-path", entry.path);
    div.setAttribute("data-depth", String(depth));
    div.style.marginLeft = `${depth * 24}px`;

    const time = entry.meta.createdAt
      ? new Date(entry.meta.createdAt).toLocaleTimeString([], {
          hour: "2-digit",
          minute: "2-digit",
        })
      : "";

    const meta = document.createElement("div");
    meta.className = "post-meta";
    meta.innerHTML = `
      <span class="post-author">${escapeHtml(entry.meta.createdBy)}</span>
      <span class="post-time">${escapeHtml(time)}</span>
    `;

    const content = document.createElement("div");
    content.className = "post-content";
    content.setAttribute("data-cy", "post-content");
    content.innerHTML = renderMarkdown(entry.doc.msg);

    const footer = document.createElement("div");
    footer.className = "post-footer";

    // Reactions
    const reactionsDiv = document.createElement("div");
    reactionsDiv.className = "post-reactions";
    const reactions = entry.doc.reactions ?? {};

    for (const rxn of REACTIONS) {
      const users: string[] = reactions[rxn.name] ?? [];
      const count = users.length;
      const reacted = users.includes(this.currentUser);

      const btn = document.createElement("button");
      btn.className = `reaction-btn${reacted ? " reacted" : ""}`;
      btn.setAttribute("data-reaction", rxn.name);
      btn.setAttribute("aria-label", `${rxn.label} (${count})`);
      btn.setAttribute("title", rxn.label);
      btn.innerHTML = `<iconify-icon icon="${rxn.icon}" aria-label="${rxn.label}"></iconify-icon><span>${count}</span>`;

      btn.addEventListener("click", () => { void this.handleReaction(entry, rxn.name); });
      reactionsDiv.appendChild(btn);
    }

    // Reply button
    const replyBtn = document.createElement("button");
    replyBtn.className = "reply-btn";
    replyBtn.setAttribute("data-cy", "reply-btn");
    replyBtn.setAttribute("aria-label", "Reply");
    replyBtn.textContent = "Reply";
    replyBtn.addEventListener("click", () => { this.setReplyTarget(entry); });

    footer.appendChild(reactionsDiv);
    footer.appendChild(replyBtn);

    div.appendChild(meta);
    div.appendChild(content);
    div.appendChild(footer);

    return div;
  }

  // ---- Reactions ----

  private async handleReaction(entry: PostEntry, reaction: string): Promise<void> {
    const current = entry.doc.reactions ?? {};
    const users: string[] = current[reaction] ?? [];
    let newUsers: string[];

    if (users.includes(this.currentUser)) {
      newUsers = users.filter((u) => u !== this.currentUser);
    } else {
      newUsers = [...users, this.currentUser];
    }

    const newReactions: Record<string, string[]> = { ...current, [reaction]: newUsers };

    try {
      await updateReactions(this.currentToken, entry.path, newReactions);
    } catch (err) {
      slog.error("Failed to update reaction", ["error", String(err)]);
      this.showError(`Error updating reaction: ${String(err)}`);
    }
  }

  // ---- Post input ----

  private setReplyTarget(entry: PostEntry): void {
    this.replyTarget = entry.path;
    const indicator = this.q<HTMLElement>(".reply-indicator");
    const excerpt = this.q<HTMLElement>(".reply-excerpt");
    if (indicator) indicator.hidden = false;
    if (excerpt) excerpt.textContent = entry.doc.msg.substring(0, 50);

    const textarea = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
    if (textarea) textarea.focus();

    this.renderPosts();
  }

  private resetInput(): void {
    this.replyTarget = null;
    const indicator = this.q<HTMLElement>(".reply-indicator");
    if (indicator) indicator.hidden = true;
    const textarea = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
    if (textarea) textarea.value = "";
  }

  private async doCreatePost(): Promise<void> {
    if (!this.currentWorkspace || !this.currentChannel) return;
    const textarea = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
    const msg = textarea.value.trim();
    if (!msg) return;

    const parent = this.replyTarget ?? "";
    textarea.value = "";
    this.resetInput();

    // Optimistic update: show post immediately without waiting for SSE
    const tempPath = `${this.currentWorkspace}/channels/${this.currentChannel}/posts/_opt_${Date.now()}`;
    const optimisticEntry: PostEntry = {
      path: tempPath,
      doc: { msg, parent: parent || undefined, reactions: {} },
      meta: { createdAt: Date.now(), createdBy: this.currentUser },
    };
    this.posts.set(tempPath, optimisticEntry);
    this.renderPosts();

    try {
      const createdPath = await createPost(
        this.currentToken,
        this.currentWorkspace,
        this.currentChannel,
        msg,
        parent,
      );
      // Replace optimistic entry with the real one (SSE will also update it)
      this.posts.delete(tempPath);
      if (createdPath && !this.posts.has(createdPath)) {
        this.posts.set(createdPath, {
          path: createdPath,
          doc: { msg, parent: parent || undefined, reactions: {} },
          meta: { createdAt: Date.now(), createdBy: this.currentUser },
        });
      }
      this.renderPosts();
    } catch (err) {
      // Remove optimistic entry on failure
      this.posts.delete(tempPath);
      this.renderPosts();
      slog.error("Failed to create post", ["error", String(err)]);
      this.showError(`Error creating post: ${String(err)}`);
    }
  }

  // ---- Formatting buttons ----

  private insertFormatting(format: string): void {
    const ta = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
    const start = ta.selectionStart;
    const end = ta.selectionEnd;
    const selected = ta.value.substring(start, end);

    if (format === "link") {
      if (selected) {
        ta.value =
          ta.value.substring(0, start) + `[${selected}](url)` + ta.value.substring(end);
        ta.selectionStart = ta.selectionEnd = start + selected.length + 3;
      } else {
        ta.value = ta.value.substring(0, start) + "[](url)" + ta.value.substring(end);
        ta.selectionStart = ta.selectionEnd = start + 1;
      }
      ta.focus();
      return;
    }

    let wrap = "";
    let extra = 0;
    if (format === "bold") {
      wrap = "**";
      extra = 4;
    } else if (format === "italic") {
      wrap = "*";
      extra = 2;
    } else {
      return;
    }

    ta.value =
      ta.value.substring(0, start) + wrap + selected + wrap + ta.value.substring(end);
    ta.selectionStart = ta.selectionEnd = selected ? end + extra : start + extra / 2;
    ta.focus();
  }

  private insertEmoji(emoji: string): void {
    const ta = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
    const pos = ta.selectionStart;
    ta.value = ta.value.substring(0, pos) + emoji + ta.value.substring(pos);
    ta.selectionStart = ta.selectionEnd = pos + emoji.length;
    ta.focus();
  }

  // ---- Logout ----

  private async doLogout(): Promise<void> {
    this.clearError();
    try {
      await logout(this.currentToken);
    } catch (err) {
      slog.warn("Logout error (ignored)", ["error", String(err)]);
    }
    this.closeCurrentWorkspace();
    const list = this.q<HTMLElement>("[data-cy='workspace-list']");
    if (list) list.innerHTML = "";
    this.currentUser = "";
    this.currentToken = "";
    this.updateUserDisplay();
    if (this.onLogoutCallback) this.onLogoutCallback();
  }

  // ---- Event handler setup ----

  private setupHandlers(): void {
    // Logout
    this.q<HTMLButtonElement>("[data-cy='logout-btn']").addEventListener("click", () => {
      void this.doLogout();
    });

    // Error dismiss
    this.q<HTMLButtonElement>(".error-dismiss").addEventListener("click", () => {
      this.clearError();
    });

    // Refresh workspaces
    this.q<HTMLButtonElement>("[data-cy='refresh-workspaces']").addEventListener("click", () => {
      void this.loadWorkspaces();
    });

    // Create workspace: button click
    this.q<HTMLButtonElement>("[data-cy='workspace-create-btn']").addEventListener("click", () => {
      void this.doCreateWorkspace();
    });

    // Create workspace: Enter key
    this.q<HTMLInputElement>("[data-cy='workspace-input']").addEventListener("keydown", (e) => {
      if ((e as KeyboardEvent).key === "Enter") void this.doCreateWorkspace();
    });

    // Refresh channels
    this.q<HTMLButtonElement>("[data-cy='refresh-channels']").addEventListener("click", () => {
      if (this.currentWorkspace) void this.loadChannels(this.currentWorkspace);
    });

    // Create channel: button click
    this.q<HTMLButtonElement>("[data-cy='channel-create-btn']").addEventListener("click", () => {
      void this.doCreateChannel();
    });

    // Create channel: Enter key
    this.q<HTMLInputElement>("[data-cy='channel-input']").addEventListener("keydown", (e) => {
      if ((e as KeyboardEvent).key === "Enter") void this.doCreateChannel();
    });

    // Post input: Enter to submit, Shift+Enter for newline
    this.q<HTMLTextAreaElement>("[data-cy='post-input']").addEventListener(
      "keydown",
      (e: Event) => {
        const ke = e as KeyboardEvent;
        if (ke.key === "Enter" && !ke.shiftKey) {
          ke.preventDefault();
          void this.doCreatePost();
        }
      },
    );

    // Post button
    this.q<HTMLButtonElement>("[data-cy='post-btn']").addEventListener("click", () => {
      void this.doCreatePost();
    });

    // Cancel reply
    this.q<HTMLButtonElement>("[data-cy='cancel-reply']").addEventListener("click", () => {
      this.resetInput();
      this.renderPosts();
    });

    // Formatting buttons
    this.shadow.querySelectorAll<HTMLButtonElement>(".fmt-btn").forEach((btn) => {
      btn.addEventListener("click", () => {
        const format = btn.getAttribute("data-format");
        if (format) this.insertFormatting(format);
      });
    });

    // Emoji buttons
    this.shadow.querySelectorAll<HTMLButtonElement>(".emoji-btn").forEach((btn) => {
      btn.addEventListener("click", () => {
        const emoji = btn.getAttribute("data-emoji");
        if (emoji) this.insertEmoji(emoji);
      });
    });

    // Hidden workspace-open-input: programmatic workspace open (for tests)
    const wsOpenInput = this.q<HTMLInputElement>("[data-cy='workspace-open-input']");
    wsOpenInput.addEventListener("keydown", (e) => {
      if ((e as KeyboardEvent).key === "Enter") {
        const name = wsOpenInput.value.trim();
        wsOpenInput.value = "";
        if (name) void this.openWorkspace(name);
      }
    });

    // Hidden workspace-delete-input: programmatic workspace delete (for tests)
    const wsDeleteInput = this.q<HTMLInputElement>("[data-cy='workspace-delete-input']");
    wsDeleteInput.addEventListener("keydown", (e) => {
      if ((e as KeyboardEvent).key === "Enter") {
        const name = wsDeleteInput.value.trim();
        wsDeleteInput.value = "";
        if (name) void this.doDeleteWorkspace(name);
      }
    });

    // Hidden channel-open-input: programmatic channel open (for tests)
    const chOpenInput = this.q<HTMLInputElement>("[data-cy='channel-open-input']");
    chOpenInput.addEventListener("keydown", (e) => {
      if ((e as KeyboardEvent).key === "Enter") {
        const name = chOpenInput.value.trim();
        chOpenInput.value = "";
        if (name) void this.openChannel(name);
      }
    });

    // Hidden channel-delete-input: programmatic channel delete (for tests)
    const chDeleteInput = this.q<HTMLInputElement>("[data-cy='channel-delete-input']");
    chDeleteInput.addEventListener("keydown", (e) => {
      if ((e as KeyboardEvent).key === "Enter") {
        const name = chDeleteInput.value.trim();
        chDeleteInput.value = "";
        if (name) void this.doDeleteChannel(name);
      }
    });
  }

