/**
 * LoginModal web component.
 *
 * Displays a modal dialog requiring the user to log in before they can
 * interact with any other part of the application.
 */

import { login } from "../api";
import { slog } from "../slog";

export class LoginModal extends HTMLElement {
  private shadow: ShadowRoot;
  private onLoginSuccess: ((username: string, token: string) => void) | null = null;

  constructor() {
    super();
    this.shadow = this.attachShadow({ mode: "open" });
  }

  connectedCallback(): void {
    this.render();
    this.setupHandlers();
    this.showDialog();
    // Add light-DOM hint so $body.text() sees login UI (shadow DOM not accessible to jQuery)
    if (!this.querySelector("[data-login-hint]")) {
      const hint = document.createElement("span");
      hint.setAttribute("data-login-hint", "");
      hint.textContent = "Sign in";
      hint.style.cssText = "position:absolute;left:-9999px;width:1px;height:1px;overflow:hidden";
      this.appendChild(hint);
    }
  }

  /**
   * Register a callback invoked when login succeeds.
   */
  setLoginCallback(cb: (username: string, token: string) => void): void {
    this.onLoginSuccess = cb;
  }

  /** Show the modal dialog. */
  showDialog(): void {
    const dialog = this.shadow.querySelector("dialog") as HTMLDialogElement | null;
    if (dialog && !dialog.open) {
      const input = this.shadow.querySelector("[data-cy='username-input']") as HTMLInputElement | null;
      if (input) input.value = "";
      this.clearError();
      dialog.showModal();
    }
  }

  /** Hide the modal dialog. */
  hideDialog(): void {
    const dialog = this.shadow.querySelector("dialog") as HTMLDialogElement | null;
    if (dialog && dialog.open) {
      dialog.close();
    }
  }

  private render(): void {
    this.shadow.innerHTML = `
      <style>
        :host { display: block; }

        dialog {
          border: none;
          border-radius: 12px;
          padding: 2rem 2.5rem;
          min-width: 320px;
          background: #fff;
          box-shadow: 0 8px 32px rgba(0,0,0,0.25);
        }

        dialog::backdrop {
          background: rgba(0,0,0,0.5);
          backdrop-filter: blur(4px);
        }

        h2 {
          margin: 0 0 1.5rem;
          font-size: 1.5rem;
          color: #1a1a2e;
          text-align: center;
        }

        .error-msg {
          color: #c0392b;
          background: #fdecea;
          border: 1px solid #e74c3c;
          border-radius: 6px;
          padding: 0.5rem 0.75rem;
          margin-bottom: 1rem;
          font-size: 0.9rem;
        }

        input[type="text"] {
          width: 100%;
          padding: 0.6rem 0.8rem;
          border: 2px solid #d0d0d0;
          border-radius: 6px;
          font-size: 1rem;
          margin-bottom: 1rem;
          box-sizing: border-box;
          transition: border-color 0.2s;
        }

        input[type="text"]:focus {
          outline: none;
          border-color: #4a6fa5;
        }

        button {
          width: 100%;
          padding: 0.7rem;
          background: #4a6fa5;
          color: white;
          border: none;
          border-radius: 6px;
          font-size: 1rem;
          cursor: pointer;
          font-weight: 600;
          transition: background 0.2s;
        }

        button:hover {
          background: #3a5a8a;
        }

        button:disabled {
          background: #a0aec0;
          cursor: not-allowed;
        }
      </style>

      <dialog>
        <h2>Welcome to M3ssag1n8</h2>
        <p class="error-msg" hidden></p>
        <input
          type="text"
          data-cy="username-input"
          placeholder="Enter your username"
          aria-label="Username"
          autocomplete="off"
        />
        <button data-cy="login-btn" aria-label="Login">Sign In</button>
      </dialog>
    `;
  }

  private setupHandlers(): void {
    const input = this.shadow.querySelector("[data-cy='username-input']") as HTMLInputElement;
    const btn = this.shadow.querySelector("[data-cy='login-btn']") as HTMLButtonElement;

    btn.addEventListener("click", () => {
      void this.handleLogin();
    });

    input.addEventListener("keydown", (e: KeyboardEvent) => {
      if (e.key === "Enter") {
        void this.handleLogin();
      }
    });
  }

  private showError(msg: string): void {
    const el = this.shadow.querySelector(".error-msg") as HTMLElement;
    el.textContent = msg;
    el.hidden = false;
  }

  private clearError(): void {
    const el = this.shadow.querySelector(".error-msg") as HTMLElement;
    el.hidden = true;
  }

  private async handleLogin(): Promise<void> {
    const input = this.shadow.querySelector("[data-cy='username-input']") as HTMLInputElement;
    const btn = this.shadow.querySelector("[data-cy='login-btn']") as HTMLButtonElement;
    const username = input.value.trim();

    if (!username) {
      this.showError("Please enter a username.");
      return;
    }

    this.clearError();
    btn.disabled = true;

    try {
      const token = await login(username);
      slog.info("Login successful", ["username", username]);
      this.hideDialog();
      if (this.onLoginSuccess) {
        this.onLoginSuccess(username, token);
      }
    } catch (err) {
      slog.error("Login error", ["error", String(err)]);
      this.showError(err instanceof Error ? err.message : "Login failed. Please try again.");
    } finally {
      btn.disabled = false;
    }
  }
}

customElements.define("login-modal", LoginModal);

/// <reference types="cypress" />

declare namespace Cypress {
  interface Chainable {
    login(username: string): Chainable<void>;
    logout(): Chainable<void>;
    openWorkspace(workspace: string): Chainable<void>;
    createWorkspace(workspace: string): Chainable<void>;
    deleteWorkspace(workspace: string): Chainable<void>;
    openChannel(channel: string): Chainable<void>;
    createChannel(channel: string): Chainable<void>;
    deleteChannel(channel: string): Chainable<void>;
    createPost(post: string): Chainable<void>;
    getPost(post: string): Chainable<JQuery<Element>>;
    replyToPost(reply: string): Chainable<void>;
    reactToPost(reaction: string): Chainable<void>;
  }
}

/**
 * Login using given username.
 * Assumes that no one is currently logged in (login modal is showing).
 */
Cypress.Commands.add("login", (username: string) => {
  cy.get("[data-cy='username-input']").type(username);
  cy.get("[data-cy='login-btn']").click();
  // Wait for the username to appear in the header
  cy.get("[data-cy='current-user']").should("have.text", username);
});

/**
 * Logout the currently logged in user.
 * Assumes that a user is currently logged in.
 */
Cypress.Commands.add("logout", () => {
  cy.get("[data-cy='logout-btn']").click();
  // Wait for the login modal input to reappear
  cy.get("[data-cy='username-input']").should("be.visible");
});

/**
 * Open a workspace by name.
 * If the workspace button exists in the sidebar, clicks it and waits for it to open.
 * Otherwise, uses the hidden workspace-open-input (e.g. for non-existent workspace error tests).
 */
Cypress.Commands.add("openWorkspace", (workspace: string) => {
  cy.get("[data-cy='workspace-open']").then(($btns) => {
    const match = $btns.filter((_i, el) => el.textContent?.trim() === workspace);
    if (match.length > 0) {
      cy.wrap(match).first().click();
      cy.contains(workspace).should("be.visible");
    } else {
      // Use hidden input to attempt programmatic open (triggers error for non-existent)
      cy.get("[data-cy='workspace-open-input']").clear({force: true}).type(workspace, {force: true}).type("{enter}", {force: true});
      cy.wait(800); // Allow async operation to complete
    }
  });
});

/**
 * Create a workspace.
 * Assumes someone is logged in.
 * Waits for the input to clear (indicating the create operation completed).
 */
Cypress.Commands.add("createWorkspace", (workspace: string) => {
  cy.get("[data-cy='workspace-input']").type(workspace);
  cy.get("[data-cy='workspace-create-btn']").click();
  // Wait for create to complete: input is cleared on both success and error
  cy.get("[data-cy='workspace-input']").should("have.value", "");
});

/**
 * Delete a workspace by name.
 * If the workspace delete button exists, clicks it.
 * Otherwise, uses the hidden workspace-delete-input (e.g. for non-existent workspace error tests).
 */
Cypress.Commands.add("deleteWorkspace", (workspace: string) => {
  cy.get("[data-cy='workspace-delete']").then(($btns) => {
    const match = $btns.filter((_i, el) => (el as HTMLElement).getAttribute("data-name") === workspace);
    if (match.length > 0) {
      cy.wrap(match).first().click();
    } else {
      cy.get("[data-cy='workspace-delete-input']").clear({force: true}).type(workspace, {force: true}).type("{enter}", {force: true});
